# In an OSC In DAT callback or Execute DAT
def onReceiveOSC(dat, rowIndex, message, address, args, port):
	"""Route OSC messages to parameters based on address pattern."""
	# Example: /slider/1 -> noise scale
	if address == '/slider/1' and len(args) > 0:
		op('noise1').par.roughness = args[0]

	# Example: /button/1 -> toggle bypass
	elif address == '/button/1' and len(args) > 0:
		op('level1').par.opacity = 1.0 if args[0] > 0.5 else 0.0

	# Example: /xy/1 -> translate X/Y
	elif address == '/xy/1' and len(args) >= 2:
		op('transform1').par.tx = args[0]
		op('transform1').par.ty = args[1]
